#!/usr/bin/env python3
"""Render qr_label — generated by doql build.

Usage:
    python render_qr_label.py [--pdf]

Requires:
    pip install jinja2
    pip install weasyprint   # only if --pdf
"""
import argparse
import json
import pathlib
import sys

try:
    from jinja2 import Environment, FileSystemLoader
except ImportError:
    print("pip install jinja2", file=sys.stderr)
    sys.exit(1)


PROJECT_ROOT = pathlib.Path(__file__).resolve().parent.parent.parent
TEMPLATE = "templates/label.html"
OUTPUT_TYPE = "html"


def load_data():
    """Load stub data — replace with real DATA source integration."""
    return {
        "app_name": "Calibration Certificate Generator",
        "version": "0.3.0",
        "document": "qr_label",
    }


def render_html(data: dict) -> str:
    template_path = PROJECT_ROOT / TEMPLATE
    if not template_path.exists():
        print(f"Template not found: {template_path}", file=sys.stderr)
        sys.exit(1)
    env = Environment(loader=FileSystemLoader(str(template_path.parent)))
    tmpl = env.get_template(template_path.name)
    return tmpl.render(**data)


def render_pdf(html: str, output: pathlib.Path):
    try:
        from weasyprint import HTML
    except ImportError:
        print("pip install weasyprint  (for PDF output)", file=sys.stderr)
        sys.exit(1)
    HTML(string=html).write_pdf(str(output))


def main():
    parser = argparse.ArgumentParser(description="Render qr_label")
    parser.add_argument("--pdf", action="store_true", help="Output PDF instead of HTML")
    parser.add_argument("-o", "--output", help="Output file path")
    args = parser.parse_args()

    data = load_data()
    html = render_html(data)

    if args.pdf or OUTPUT_TYPE == "pdf":
        out = pathlib.Path(args.output or "qr_label.pdf")
        render_pdf(html, out)
        print(f"PDF → {out}")
    else:
        out = pathlib.Path(args.output or "qr_label.html")
        out.write_text(html, encoding="utf-8")
        print(f"HTML → {out}")


if __name__ == "__main__":
    main()
